additionalSteps.code:
def addMissingType:
if .type then .
elif .items then . + {type: "Catalog"}
elif .concepts then . + {type: "ConceptScheme"}
elif .id then . + {type: "Concept"}
else .
end;

def walkEntities:
addMissingType |
if .items then .items |= map(if type == "object" then walkEntities else . end) else . end |
if .concepts then .concepts |= map(walkEntities) else . end |
if .members then .members |= map(walkEntities) else . end |
if .narrower then .narrower |= map(if type == "object" then walkEntities else . end) else . end;

if type == "array" then map(walkEntities) else walkEntities end

PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
INSERT {
  ?a skos:broader ?b .
  ?b skos:narrower ?a .
} WHERE {
  ?a skos:broader|^skos:narrower ?b
}

PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
INSERT {
  ?y skos:inScheme ?cs .
} WHERE {
  ?x skos:inScheme ?cs .
  ?x skos:narrower+ ?y .
}

PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
INSERT {
  ?c skos:topConceptOf ?cs .
  ?cs skos:hasTopConcept ?c .
} WHERE {
  ?c skos:inScheme ?cs .
  FILTER NOT EXISTS { ?c skos:broader|^skos:narrower ?broader . ?broader skos:inScheme ?cs }
}
